sql:
SELECT player_id, losses
FROM player_performance
WHERE losses = (
    SELECT MAX(losses) 
    FROM player_performance
);

SELECT player_name, team_id
FROM players
WHERE player_id > 100 AND team_id IS NOT NULL;

SELECT COUNT(*) AS total_awards
FROM awards
WHERE player_id = 'Your Player ID';

SELECT SUM(games_played) AS total_games_played
FROM player_performance
WHERE player_id = 'Your Specific Player ID Here';

